@dataclass
class Obstacle:
    id: str
    position: Vector3
    size: Vector3
    obstacle_type: str
    destructible: bool = False
    health: float = 100.0

    def to_dict(self):
        return {
            "id": self.id,
            "position": self.position.to_dict(),
            "size": self.size.to_dict(),
            "obstacle_type": self.obstacle_type,
            "destructible": self.destructible,
            "health": self.health,
        }

    def contains_point_2d(self, point: Vector3) -> bool:
        return (
            self.position.x - self.size.x / 2 <= point.x <= self.position.x + self.size.x / 2 and
            self.position.y - self.size.y / 2 <= point.y <= self.position.y + self.size.y / 2
        )


@dataclass
class Player:
    id: str
    name: str
    position: Vector3 = field(default_factory=Vector3)
